module up_down_counter(
    input clk,
    input rst,
    input ctrl,

    output [2:0] count
);

reg [2:0] count;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt)
begin
  if (rst)
    count <= 3'b000;
  else if (ctrl)
    count <= (count == 3'b111) ? 3'b000 : count + 1;
  else
    count <= (count == 3'b000) ? 3'b111 : count - 1;
end

endmodule
